private fun calendarPrayerTime(
    date: String,
    fajrBegins: String,
    fajrJamaah: String,
    sunrise: String,
    dhuhrBegins: String,
    dhuhrJamaah: String,
    asrBegins: String,
    asrJamaah: String,
    maghribBegins: String,
    maghribJamaah: String,
    ishaBegins: String,
    ishaJamaah: String,
): CalendarPrayerTime {
    return CalendarPrayerTime(
        date = date,
        fajrBegins = fajrBegins,
        fajrJamaah = fajrJamaah,
        sunrise = sunrise,
        dhuhrBegins = dhuhrBegins,
        dhuhrJamaah = dhuhrJamaah,
        asrBegins = asrBegins,
        asrJamaah = asrJamaah,
        maghribBegins = maghribBegins,
        maghribJamaah = maghribJamaah,
        ishaBegins = ishaBegins,
        ishaJamaah = ishaJamaah,
    )
}
